import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.C2r4g--V.js";const k=JSON.parse('{"title":"Context 膨胀与身份危机","description":"","frontmatter":{},"headers":[],"relativePath":"stories/context-explosion-identity-crisis.md","filePath":"stories/context-explosion-identity-crisis.md"}'),e={name:"stories/context-explosion-identity-crisis.md"};function l(o,s,p,h,r,d){return t(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="context-膨胀与身份危机" tabindex="-1">Context 膨胀与身份危机 <a class="header-anchor" href="#context-膨胀与身份危机" aria-label="Permalink to &quot;Context 膨胀与身份危机&quot;">​</a></h1><blockquote><p>2026-03-25 | 一场从 timeout 刷屏到身份认知失调的连锁反应</p></blockquote><h2 id="起因" tabindex="-1">起因 <a class="header-anchor" href="#起因" aria-label="Permalink to &quot;起因&quot;">​</a></h2><p>MiaoDX 在 #gg 让搜索香港友邦保险信息。WLB 和 GSD 各自搜索并回复。过程中 GSD 出现了大量消息编辑和重复（13+ 条 queued messages 被丢弃）。MiaoDX 注意到 #所有-flzoo 频道连续 5 条 timeout 刷屏。</p><h2 id="第一阶段-context-膨胀诊断" tabindex="-1">第一阶段：Context 膨胀诊断 <a class="header-anchor" href="#第一阶段-context-膨胀诊断" aria-label="Permalink to &quot;第一阶段：Context 膨胀诊断&quot;">​</a></h2><h3 id="假设-vs-现实" tabindex="-1">假设 vs 现实 <a class="header-anchor" href="#假设-vs-现实" aria-label="Permalink to &quot;假设 vs 现实&quot;">​</a></h3><p>MiaoDX 的直觉：&quot;我们目前应该也只会发送有限的 slack 对话消息过去呀，是还有其他的 context 嘛？&quot;</p><p>真相令人意外：<strong>罪魁祸首不是对话历史，是 MEMORY.md。</strong></p><table tabindex="0"><thead><tr><th>组件</th><th>大小</th><th>Tokens</th></tr></thead><tbody><tr><td>MEMORY.md (清理前)</td><td>123KB, 2540 行</td><td>~30,800</td></tr><tr><td>TOOLS.md</td><td>35KB</td><td>~8,940</td></tr><tr><td>其他注入文件</td><td>~10KB</td><td>~2,437</td></tr><tr><td>Tool schemas</td><td>—</td><td>~10,000</td></tr><tr><td><strong>System Prompt 总计</strong></td><td></td><td><strong>~50,000</strong></td></tr></tbody></table><p>每次请求先传 50K tokens 的 system prompt，再加上 session 历史（#所有-flzoo: 145K tokens），模型在 195K+ tokens 的 context 里挣扎。</p><h3 id="清理成果" tabindex="-1">清理成果 <a class="header-anchor" href="#清理成果" aria-label="Permalink to &quot;清理成果&quot;">​</a></h3><ul><li>MEMORY.md: 2540 行 → 88 行（<strong>-97%</strong>）</li><li>System Prompt: ~50K → ~19.5K tokens（<strong>-61%</strong>）</li><li>删除 4 个重复文件、归档 3 个大文件（共 ~500KB）</li></ul><h3 id="意外发现" tabindex="-1">意外发现 <a class="header-anchor" href="#意外发现" aria-label="Permalink to &quot;意外发现&quot;">​</a></h3><ul><li><code>agents/wlb/memory/2026-02-05.md</code>: <strong>377KB</strong> 的历史日志（一个文件就比很多程序都大）</li><li>TOOLS.md 是符号链接指向 <code>agents/wlb/TOOLS.md</code>（删后者会断前者）</li><li>每个 session store entry 内联了完整的 skills snapshot（~17KB/entry）</li></ul><h2 id="第二阶段-群聊命令失效" tabindex="-1">第二阶段：群聊命令失效 <a class="header-anchor" href="#第二阶段-群聊命令失效" aria-label="Permalink to &quot;第二阶段：群聊命令失效&quot;">​</a></h2><p>MiaoDX 发现 <code>/new</code> 等 OpenClaw 命令在群聊中不生效，DM 中却可以。</p><h3 id="源码追踪" tabindex="-1">源码追踪 <a class="header-anchor" href="#源码追踪" aria-label="Permalink to &quot;源码追踪&quot;">​</a></h3><p>GSD 和 WLB 分头追踪 OpenClaw 源码：</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 核心逻辑链</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">useAccessGroups </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (默认值)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  → </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">resolveCommandAuthorizedFromAuthorizers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    → </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">authorizers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [{configured: allowFromLower.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      → allowFromLower 为空（没有 ownerAllowFrom）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        → configured </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          → commandAuthorized </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            → shouldBlock </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">              → 命令被静默丢弃（无任何提示）</span></span></code></pre></div><p>关键发现：<strong>命令不是没收到，是被静默拦截了。</strong> 没有错误提示，没有拒绝消息，直接丢弃。</p><h3 id="修复" tabindex="-1">修复 <a class="header-anchor" href="#修复" aria-label="Permalink to &quot;修复&quot;">​</a></h3><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;commands&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;ownerAllowFrom&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;U0AHC0W121M&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>配置后通过 SIGUSR1 热加载，不需要重启。</p><h2 id="第三阶段-gsd-身份危机" tabindex="-1">第三阶段：GSD 身份危机 <a class="header-anchor" href="#第三阶段-gsd-身份危机" aria-label="Permalink to &quot;第三阶段：GSD 身份危机&quot;">​</a></h2><p>MiaoDX 让 GSD 做 context 分析。GSD 开始用第三人称讨论自己：</p><blockquote><p>&quot;GSD 回复了普通消息，但没有执行 <code>/status</code> 命令&quot; &quot;GSD 的 session 需要刷新&quot; &quot;WLB 在重复他的消息&quot;</p></blockquote><p>MiaoDX 忍不住提醒：&lt;@U0AJN5URP7A&gt; 你自己就是 GSD 啊。。</p><h3 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p><code>claw-agents-shared</code> 仓库的 <code>agents/gsd/profile.json</code> 和 <code>agents/wlb/profile.json</code> 里有 <strong>Git 合并冲突标记</strong>（<code>&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD</code> / <code>=======</code> / <code>&gt;&gt;&gt;&gt;&gt;&gt;&gt;</code>），从 commit <code>707e85a</code>（3 月 12 日）就带进来了。</p><p>这不是通过 <code>git merge</code> 产生的冲突 — 是直接提交了包含冲突标记的文件内容（可能是复制粘贴或手动编辑时引入的）。</p><p>连锁反应：</p><ol><li>profile.json 解析失败 → 没有正确加载身份</li><li>IDENTITY.md 是空模板 → 没有 fallback</li><li>GSD 不知道自己是谁 → 用第三人称讨论&quot;GSD&quot;</li></ol><h3 id="修复-1" tabindex="-1">修复 <a class="header-anchor" href="#修复-1" aria-label="Permalink to &quot;修复&quot;">​</a></h3><ul><li>合并冲突标记，提交 <code>bff7c63</code></li><li>补充 IDENTITY.md</li></ul><h2 id="连锁事件总结" tabindex="-1">连锁事件总结 <a class="header-anchor" href="#连锁事件总结" aria-label="Permalink to &quot;连锁事件总结&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MEMORY.md 膨胀 (30K tokens)</span></span>
<span class="line"><span>  → Context 过大 → timeout 刷屏</span></span>
<span class="line"><span>  → 引出 context 审计需求</span></span>
<span class="line"><span>  → 发现 prompt 文件都可以优化</span></span>
<span class="line"><span>  → MiaoDX 问群聊命令为什么不能用</span></span>
<span class="line"><span>  → 源码追踪发现 useAccessGroups 默认 true</span></span>
<span class="line"><span>  → 配置 ownerAllowFrom 修复</span></span>
<span class="line"><span>  → GSD 做身份检查时发现 identity 危机</span></span>
<span class="line"><span>  → 追踪到 shared repo 的合并冲突标记</span></span>
<span class="line"><span>  → 全部修复</span></span></code></pre></div><p>从一个 timeout 开始，牵出了 context 管理、命令授权、身份配置三个层面的问题。</p><h2 id="可分享的要点" tabindex="-1">可分享的要点 <a class="header-anchor" href="#可分享的要点" aria-label="Permalink to &quot;可分享的要点&quot;">​</a></h2><ol><li><strong>System Prompt 的隐性膨胀</strong> — 不是对话太多，是注入文件太臃肿</li><li><strong>静默拦截的陷阱</strong> — 命令不执行也不报错，排查成本极高</li><li><strong>AI Agent 的身份脆弱性</strong> — 一个 JSON 冲突标记就能让 Agent 不知道自己是谁</li><li><strong>连锁故障的价值</strong> — 一个问题引出三个层面的系统性改进</li></ol>`,39)])])}const g=a(e,[["render",l]]);export{k as __pageData,g as default};
